#include <bits/stdc++.h>
using namespace std;
const int maxn=1005;
int n,m,a[maxn][maxn],d[maxn];
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1,x,y;i<=m;i++){
		cin>>x>>y;
		a[x][y]=a[y][x]=1;
		d[x]++,d[y]++;
	}
	for(int i=1;i<=n;i++,cout<<"\n"){
		for(int j=1;j<=n;j++){
			cout<<a[i][j]<<" ";
		}
	}
	for(int i=1;i<=n;i++,cout<<"\n"){
		cout<<d[i]<<" ";
		for(int j=1;j<=n;j++){
			a[i][j]&&cout<<j<<" ";
		}
	}
	return 0;
}
